import std/strutils
import atcoder/extra/numeric/float128

proc emitValid(index: int; text: string) =
  var destination = fromBits(
    0xFFFF_FFFF_FFFF_FFFF'u64,
    0xFFFF_FFFF_FFFF_FFFF'u64,
  )

  let
    valid = tryParseFloat128(text, destination)
    destinationBits = toBits(destination)
    parsedBits = toBits(parseFloat128(text))

  echo "VALID\t", index, "\t",
    valid, "\t",
    toHex(destinationBits.high, 16), "\t",
    toHex(destinationBits.low, 16), "\t",
    toHex(parsedBits.high, 16), "\t",
    toHex(parsedBits.low, 16)

proc emitInvalid(index: int; text: string) =
  var destination = fromBits(
    0xFFFF_FFFF_FFFF_FFFF'u64,
    0xFFFF_FFFF_FFFF_FFFF'u64,
  )

  let valid = tryParseFloat128(text, destination)
  let destinationBits = toBits(destination)

  var raised = false

  try:
    discard parseFloat128(text)
  except ValueError:
    raised = true

  echo "INVALID\t", index, "\t",
    valid, "\t",
    toHex(destinationBits.high, 16), "\t",
    toHex(destinationBits.low, 16), "\t",
    raised

